#!/usr/bin/env python3
"""
Eagle 3D Streaming - Deploy v4.0
================================
Run this in your eagle3d-kpi-automation folder:
    python3 deploy_v4.py
"""
import base64, os, shutil
from datetime import datetime

APP_B64 = ""

DASHBOARD_PY = """# dashboard.py - Redirect to app.py (v4)
import os, runpy
os.environ.setdefault('STREAMLIT_SERVER_HEADLESS', 'true')
runpy.run_path('app.py', run_name='__main__')
"""

CONFIG_TOML = """[server]
headless = true
maxUploadSize = 200

[browser]
gatherUsageStats = false

[theme]
base = "dark"
primaryColor = "#00D4FF"
backgroundColor = "#0B1120"
secondaryBackgroundColor = "#162032"
textColor = "#E8EDF5"
"""

SECRETS_TOML = """groq_api_key = os.environ.get("GROQ_API_KEY", "")"
gemini_api_key = os.environ.get("GEMINI_API_KEY", "")"
"""

print()
print("=" * 60)
print("  Eagle 3D Streaming - KPI Dashboard v4.0 Deploy")
print("=" * 60)
print()

# 1. Backup
if os.path.exists("app.py"):
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    shutil.copy2("app.py", f"app.py.backup_{ts}")
if os.path.exists("dashboard.py"):
    shutil.copy2("dashboard.py", f"dashboard.py.backup_{ts}")
print("  [1/6] Backed up old files")

# 2. Write new app.py
with open("app.py", "wb") as f:
    f.write(base64.b64decode(APP_B64))
print("  [2/6] Wrote new app.py (v4.0)")

# 3. Write dashboard.py redirect (CRITICAL for Streamlit Cloud)
with open("dashboard.py", "w") as f:
    f.write(DASHBOARD_PY)
print("  [3/6] Wrote dashboard.py -> redirects to app.py")
print("         (Streamlit Cloud uses dashboard.py as main file)")

# 4. Write config.toml
os.makedirs(".streamlit", exist_ok=True)
with open(".streamlit/config.toml", "w") as f:
    f.write(CONFIG_TOML)
print("  [4/6] Fixed .streamlit/config.toml")

# 5. Write secrets.toml if missing
if not os.path.exists(".streamlit/secrets.toml"):
    with open(".streamlit/secrets.toml", "w") as f:
        f.write(SECRETS_TOML)
    print("  [5/6] Created .streamlit/secrets.toml")
else:
    print("  [5/6] secrets.toml exists (kept)")

# 6. Git commit everything
import subprocess
subprocess.run(["git", "config", "user.email", "eagle3d@automation.dev"], capture_output=True)
subprocess.run(["git", "config", "user.name", "Eagle3D Automation"], capture_output=True)
subprocess.run(["git", "add", "app.py", "dashboard.py", ".streamlit/config.toml"], capture_output=True)
subprocess.run(["git", "commit", "-m", "v4.0: fix crash, dark/light mode, dashboard.py redirect"], capture_output=True, text=True)
print("  [6/6] Git committed")

print()
print("=" * 60)
print("  DEPLOY COMPLETE!")
print("=" * 60)
print()
print("  Now push to go live:")
print()
print("    git push origin main")
print()
print("  If rejected:")
print()
print("    git push --force-with-lease origin main")
print()
print("  Then hard refresh the live site: Cmd + Shift + R")
print("=" * 60)